// Cargo.toml: tokio = { version = "1", features = ["full"] }

#[tokio::main]
async fn main() {
    println!("Running on tokio!");
    let result = do_work().await;
    println!("Result: {}", result);
}

async fn do_work() -> u32 {
    42
}

use tokio::runtime::Runtime;

fn main() {
    let rt = Runtime::new().unwrap();

    rt.block_on(async {
        println!("Running inside manually created runtime");
        let value = async_computation().await;
        println!("Got: {}", value);
    });
}

async fn async_computation() -> String {
    "computed".to_string()
}

#[tokio::main(flavor = "current_thread")]
async fn main() {
    // Runs everything on a single thread
    // Good for: testing, embedded, WASM
    println!("Single-threaded runtime");
}

